<template>
    <div class="padding-t_10" id="reportstabsdata">
        <div class="left-menu-tab new_tab">
            <div class="col-md-12 p-0">
                <div class="theme-primary partition">
                    <span class="p-name text-white">Hr Reports</span>
                </div>
            </div>            
            <div class="mt-2" id="divscrollsetuptabs" style="max-height: 700px">
                <ul class="nav nav-pills flex-column left-tab responivecustomtab lefttabiconfix lefttabflexible" id="upper" role="tablist">
                    <li v-for="(tab, index) in filteredTabs" :key="index">
                        <a class="nav-link left-menu" :data-toggle="'#' + tab.id" :class="{ active: activeKey === tab.index }" @click="activateTab(tab.index)">
                            <i :class="tab.icon" aria-hidden="true"></i>{{ $t(tab.name) }}
                        </a>
                    </li>
                </ul>
            </div>
        </div>
    
        <!-- right-content here -->
        <div class="right-content">
            <loader :isVisible="isLoading"></loader>
            <div class="col-md-12 p-0">
                <div class="theme-primary partition" style="overflow: visible">
                    <span class="p-name text-white" id="spnreporttext">{{
                this.$t(activeTabName)
              }}</span>
                </div>
            </div>
            <div class="col-md-12 p-0">
                <div class="tab-content" id="myTabContent">
                    <div class="expand-list">
                        <a href="javascript:;" class="expand-list-btn justify-content-center align-items-center">
                            <i class="icon-solid arrow-solid-left text-white" style="font-size: 9pt"></i>
                        </a>
                    </div>
                    <div id="MonthlyReport" class="tab-pane" :class="{ 'active show': activeKey == 0 }" v-if="activeKey == 0">
                        <MonthlyReport></MonthlyReport>
                    </div>
                    <div id="UserLeaveBalance" class="tab-pane" :class="{ 'active show': activeKey == 1 }" v-if="activeKey == 1">
                        <UserLeaveBalance></UserLeaveBalance>
                    </div>
                    <div id="LeaveDetail" class="tab-pane" :class="{ 'active show': activeKey == 2 }" v-if="activeKey == 2">
                        <LeaveDetail></LeaveDetail>
                    </div>
                    <div id="UserExperience" class="tab-pane" :class="{ 'active show': activeKey == 3 }" v-if="activeKey == 3">
                        <UserExperienceReport></UserExperienceReport>
                    </div>
                    <div id="UserInfoReport" class="tab-pane" :class="{ 'active show': activeKey == 4 }" v-if="activeKey == 4">
                        <UserInfoReport></UserInfoReport>
                    </div>
                    <div id="DailyAttendanceReport" class="tab-pane" :class="{ 'active show': activeKey == 5 }" v-if="activeKey == 5">
                        <DailyAttendanceReport></DailyAttendanceReport>
                    </div>
                    <div id="UserAliasreport" class="tab-pane" :class="{ 'active show': activeKey == 6 }" v-if="activeKey == 6">
                        <UserAliasreport></UserAliasreport>
                    </div>
                    <div id="LeavePending" class="tab-pane" :class="{ 'active show': activeKey == 7 }" v-if="activeKey == 7">
                        <LeavePending></LeavePending>
                    </div>
                    <div id="LeaveApproved" class="tab-pane" :class="{ 'active show': activeKey == 8 }" v-if="activeKey == 8">
                        <LeaveApproved></LeaveApproved>
                    </div>
                    <div id="Hiring" class="tab-pane" :class="{ 'active show': activeKey == 9 }" v-if="activeKey == 9">
                        <Hiring></Hiring>
                    </div>
                   
                </div>
            </div>
        </div>
        <!-- right-content End here -->
    </div>
    </template>
    
    <script>
    
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
    import MonthlyReport from "../../views/HrReport/MonthlyReport.vue";
    import UserLeaveBalance from "../../views/HrReport/UserLeaveBalance.vue";
    import LeaveDetail from "../../views/HrReport/LeaveDetailReport.vue";
    import UserExperienceReport from "../../views/HrReport/UserExperienceReport.vue";
    import UserInfoReport from "../../views/HrReport/UserInfoReport.vue";
    import DailyAttendanceReport from "../../views/HrReport/DailyAttendanceReport.vue";
    import UserAliasreport from "../../views/HrReport/UserAliasreport.vue";
    import LeavePending from "../../views/HrReport/LeavePending.vue";
    import LeaveApproved from "../../views/HrReport/LeaveApproved.vue";
    import Hiring from "../../views/HrReport/Hiring.vue";
    
    export default {
        components: {
            MonthlyReport,
            UserLeaveBalance,
            LeaveDetail,
            UserExperienceReport,
            UserInfoReport,
            DailyAttendanceReport,
            UserAliasreport,
            LeavePending,
            LeaveApproved,
            Hiring
         },
        data() {
            return {
                activeKey: 0,
                tabNames: [
                    "MonthlyReport",
                    "User Leave Balance",
                    "Leave Detail",
                    "User Experience",
                    "User Info Report",
                    "Daily Attendance Report",
                    "User Alias report",
                    "Leave Pending By Approver",
                    "Leave Approved",
                    "Hiring"
                ],
                searchQuery: "",
            };
        },
        mounted() {
            this.activateTab(0);
        },
        created:function(){
            
        },
        computed: {
        filteredTabs() {
            if (!this.searchQuery) {           
                return this.tabNames.map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }));
            }
            const query = this.searchQuery.toLowerCase();
            const filtered = this.tabNames
                .map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }))
                .filter(tab => this.$t(tab.name).toLowerCase().includes(query));
    
            if (query.trim() !== '' && filtered.length === 0) {           
                return [{ name: 'No tabs found for "' + this.searchQuery + '"', index: -1, icon: 'no-icon' }];
            }
    
            return filtered;
        },
        activeTabName() {
            return this.tabNames[this.activeKey]; // Returns the name of the currently active tab
        }
    },
    
        methods: {
            getTabIcon(name) {
                switch (name) {
                    case "MonthlyReport":
                        return "fa fa-file-pdf-o";
                    case "User Leave Balance":
                        return "fa fa-file-text";
                    case "Leave Detail":
                        return "fa fa-ticket";
                    case "User Experience":
                        return "fa fa-print";
                    case "User Info Report":
                        return "fa fa-user-circle";
                    case "Daily Attendance Report":
                        return "fa fa-list-alt";
                        case "User Alias report":
                        return "fa fa-columns";
                        case "Leave Pending By Approver":
                        return "fa fa-bar-chart";
                        case "Leave Approved":
                        return "fa fa-columns";
                        case "Hiring":
                        return "fa fa-money";
                    default:
                        return "";
                }
            },
            activateTab(index) {
                debugger;
                this.activeKey = index;
            },
        },
    };
    </script>
    